using UnityEngine;
using UnityEngine.Purchasing;
using System;

public class PlayerStats : MonoBehaviour
{
    [Header("Core Stats (Public)")]
    public int level = 1;
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int baseDamage = 10;
    public float critChance = 0.1f;
    public float critMultiplier = 2.0f;

    [Header("Economy (Public)")]
    public int softCurrency = 0;
    public int premiumCurrency = 0;

    [Header("Upgrades (Public)")]
    public int damageUpgradeLevel = 0;
    public int healthUpgradeLevel = 0;

    [Header("Scaling (Public)")]
    public int damagePerUpgrade = 2;
    public int healthPerUpgrade = 10;

    [Header("Runtime (Public)")]
    public bool isDead = false;

    public event Action<int, int> OnHealthChanged;
    public event Action<int, int> OnCurrencyChanged;
    public event Action OnDied;

    void Awake()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, GetMaxHealth());
        isDead = currentHealth <= 0;
    }

    public int GetMaxHealth()
    {
        return maxHealth + healthUpgradeLevel * healthPerUpgrade;
    }

    public int GetBaseDamage()
    {
        return baseDamage + damageUpgradeLevel * damagePerUpgrade;
    }

    public int CalculateDamage(System.Random rng = null)
    {
        int dmg = Mathf.Max(1, GetBaseDamage());
        float roll = (rng != null) ? (float)rng.NextDouble() : UnityEngine.Random.value;
        bool crit = roll < Mathf.Clamp01(critChance);
        if (crit)
        {
            dmg = Mathf.Max(1, Mathf.RoundToInt(dmg * Mathf.Max(1f, critMultiplier)));
        }
        return dmg;
    }

    public void Heal(int amount)
    {
        if (amount <= 0) return;
        if (isDead) return;

        int old = currentHealth;
        currentHealth = Mathf.Clamp(currentHealth + amount, 0, GetMaxHealth());
        if (currentHealth != old) OnHealthChanged?.Invoke(currentHealth, GetMaxHealth());
    }

    public void TakeDamage(int amount)
    {
        if (amount <= 0) return;
        if (isDead) return;

        int old = currentHealth;
        currentHealth = Mathf.Clamp(currentHealth - amount, 0, GetMaxHealth());
        if (currentHealth != old) OnHealthChanged?.Invoke(currentHealth, GetMaxHealth());

        if (currentHealth <= 0 && !isDead)
        {
            isDead = true;
            OnDied?.Invoke();
        }
    }

    public void ReviveFull()
    {
        isDead = false;
        currentHealth = GetMaxHealth();
        OnHealthChanged?.Invoke(currentHealth, GetMaxHealth());
    }

    public bool SpendSoft(int amount)
    {
        if (amount <= 0) return true;
        if (softCurrency < amount) return false;

        softCurrency -= amount;
        OnCurrencyChanged?.Invoke(softCurrency, premiumCurrency);
        return true;
    }

    public bool SpendPremium(int amount)
    {
        if (amount <= 0) return true;
        if (premiumCurrency < amount) return false;

        premiumCurrency -= amount;
        OnCurrencyChanged?.Invoke(softCurrency, premiumCurrency);
        return true;
    }

    public void AddSoft(int amount)
    {
        if (amount <= 0) return;
        softCurrency += amount;
        OnCurrencyChanged?.Invoke(softCurrency, premiumCurrency);
    }

    public void AddPremium(int amount)
    {
        if (amount <= 0) return;
        premiumCurrency += amount;
        OnCurrencyChanged?.Invoke(softCurrency, premiumCurrency);
    }
}

public enum CurrencyType
{
    Soft,
    Premium
}

[Serializable]
public class ShopItemDefinition
{
    public string id = "damage_upgrade";
    public string displayName = "Damage Upgrade";
    public CurrencyType currency = CurrencyType.Soft;

    [Header("Pricing")]
    public int basePrice = 50;
    public float priceGrowth = 1.15f;
    public int maxPurchases = -1;

    [Header("Effects")]
    public int addDamageUpgradeLevels = 1;
    public int addHealthUpgradeLevels = 0;
    public int healAmount = 0;

    public int GetPriceForPurchaseIndex(int purchaseIndex)
    {
        if (purchaseIndex < 0) purchaseIndex = 0;
        double price = basePrice * Math.Pow(Math.Max(1e-6, priceGrowth), purchaseIndex);
        int rounded = Mathf.Max(0, (int)Math.Round(price, MidpointRounding.AwayFromZero));
        return rounded;
    }
}

public class ShopManager : MonoBehaviour
{
    [Header("References")]
    public PlayerStats player;

    [Header("Catalog")]
    public ShopItemDefinition[] items;

    [Header("Purchase Counters (Public)")]
    public int[] purchaseCounts;

    void Awake()
    {
        if (player == null) player = FindFirstObjectByType<PlayerStats>();

        if (items == null) items = Array.Empty<ShopItemDefinition>();
        if (purchaseCounts == null || purchaseCounts.Length != items.Length)
        {
            purchaseCounts = new int[items.Length];
        }
    }

    public ShopItemDefinition GetItemById(string id, out int index)
    {
        index = -1;
        if (items == null) return null;
        for (int i = 0; i < items.Length; i++)
        {
            if (items[i] != null && string.Equals(items[i].id, id, StringComparison.Ordinal))
            {
                index = i;
                return items[i];
            }
        }
        return null;
    }

    public int GetCurrentPrice(string itemId)
    {
        var item = GetItemById(itemId, out int idx);
        if (item == null) return -1;
        int count = (idx >= 0 && idx < purchaseCounts.Length) ? purchaseCounts[idx] : 0;
        return item.GetPriceForPurchaseIndex(count);
    }

    public bool CanPurchase(string itemId)
    {
        var item = GetItemById(itemId, out int idx);
        if (item == null || player == null) return false;

        int count = purchaseCounts[idx];
        if (item.maxPurchases >= 0 && count >= item.maxPurchases) return false;

        int price = item.GetPriceForPurchaseIndex(count);
        if (item.currency == CurrencyType.Soft) return player.softCurrency >= price;
        return player.premiumCurrency >= price;
    }

    public bool Purchase(string itemId)
    {
        var item = GetItemById(itemId, out int idx);
        if (item == null || player == null) return false;

        int count = purchaseCounts[idx];
        if (item.maxPurchases >= 0 && count >= item.maxPurchases) return false;

        int price = item.GetPriceForPurchaseIndex(count);

        bool paid = item.currency switch
        {
            CurrencyType.Soft => player.SpendSoft(price),
            CurrencyType.Premium => player.SpendPremium(price),
            _ => false
        };

        if (!paid) return false;

        ApplyItemEffects(item);
        purchaseCounts[idx] = count + 1;
        return true;
    }

    void ApplyItemEffects(ShopItemDefinition item)
    {
        if (item == null || player == null) return;

        if (item.addDamageUpgradeLevels != 0)
            player.damageUpgradeLevel = Mathf.Max(0, player.damageUpgradeLevel + item.addDamageUpgradeLevels);

        if (item.addHealthUpgradeLevels != 0)
        {
            int oldMax = player.GetMaxHealth();
            player.healthUpgradeLevel = Mathf.Max(0, player.healthUpgradeLevel + item.addHealthUpgradeLevels);
            int newMax = player.GetMaxHealth();
            if (!player.isDead)
            {
                int delta = newMax - oldMax;
                if (delta > 0)
                {
                    player.currentHealth = Mathf.Clamp(player.currentHealth + delta, 0, newMax);
                    player.OnHealthChanged?.Invoke(player.currentHealth, newMax);
                }
            }
        }

        if (item.healAmount > 0)
            player.Heal(item.healAmount);
    }
}

public class CombatExample : MonoBehaviour
{
    public PlayerStats player;
    public int enemyHealth = 50;

    void Awake()
    {
        if (player == null) player = FindFirstObjectByType<PlayerStats>();
    }

    public int PlayerAttack()
    {
        if (player == null || player.isDead) return 0;

        int dmg = player.CalculateDamage();
        enemyHealth = Mathf.Max(0, enemyHealth - dmg);
        return dmg;
    }

    public void EnemyAttack(int enemyDamage)
    {
        if (player == null) return;
        player.TakeDamage(enemyDamage);
    }
}

public class IAPManager : MonoBehaviour, IStoreListener
{
    [Header("References")]
    public PlayerStats player;

    [Header("IAP Product IDs")]
    public string premiumPackSmall = "premium_pack_small";
    public string premiumPackMedium = "premium_pack_medium";
    public string premiumPackLarge = "premium_pack_large";

    [Header("Rewards (Public)")]
    public int premiumSmallAmount = 100;
    public int premiumMediumAmount = 250;
    public int premiumLargeAmount = 600;

    IStoreController controller;
    IExtensionProvider extensions;

    void Awake()
    {
        if (player == null) player = FindFirstObjectByType<PlayerStats>();
    }

    void Start()
    {
        InitializePurchasing();
    }

    public void InitializePurchasing()
    {
        if (controller != null) return;

        var builder = ConfigurationBuilder.Instance(StandardPurchasingModule.Instance());
        builder.AddProduct(premiumPackSmall, ProductType.Consumable);
        builder.AddProduct(premiumPackMedium, ProductType.Consumable);
        builder.AddProduct(premiumPackLarge, ProductType.Consumable);

        UnityPurchasing.Initialize(this, builder);
    }

    public bool IsInitialized()
    {
        return controller != null && extensions != null;
    }

    public void BuySmall() => BuyProductID(premiumPackSmall);
    public void BuyMedium() => BuyProductID(premiumPackMedium);
    public void BuyLarge() => BuyProductID(premiumPackLarge);

    public void BuyProductID(string productId)
    {
        if (!IsInitialized()) return;
        Product product = controller.products.WithID(productId);
        if (product != null && product.availableToPurchase)
        {
            controller.InitiatePurchase(product);
        }
    }

    public void OnInitialized(IStoreController controller, IExtensionProvider extensions)
    {
        this.controller = controller;
        this.extensions = extensions;
    }

    public void OnInitializeFailed(InitializationFailureReason error) { }
#if UNITY_2022_2_OR_NEWER
    public void OnInitializeFailed(InitializationFailureReason error, string message) { }
#endif

    public PurchaseProcessingResult ProcessPurchase(PurchaseEventArgs args)
    {
        if (player == null) return PurchaseProcessingResult.Complete;

        string id = args.purchasedProduct.definition.id;

        if (string.Equals(id, premiumPackSmall, StringComparison.Ordinal))
            player.AddPremium(premiumSmallAmount);
        else if (string.Equals(id, premiumPackMedium, StringComparison.Ordinal))
            player.AddPremium(premiumMediumAmount);
        else if (string.Equals(id, premiumPackLarge, StringComparison.Ordinal))
            player.AddPremium(premiumLargeAmount);

        return PurchaseProcessingResult.Complete;
    }

    public void OnPurchaseFailed(Product product, PurchaseFailureReason failureReason) { }
}